import React, { useState, useEffect } from 'react';
import { Container, Row, Col, Card, Button, Form, InputGroup } from 'react-bootstrap';
import { Shop, ArrowRight, Search, GeoAlt } from 'react-bootstrap-icons';
import { useNavigate } from 'react-router-dom';
import { publicApi } from '../../services/api';
import { SkeletonCard, SkeletonText } from '../../components/SkeletonLoader';

function BusinessList() {
  const navigate = useNavigate();
  const [businesses, setBusinesses] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [search, setSearch] = useState('');

  useEffect(() => {
    loadBusinesses();
  }, []);

  const loadBusinesses = async () => {
    try {
      const data = await publicApi.getBusinesses();
      setBusinesses(data);
    } catch (err) {
      setError('Error al cargar negocios');
    } finally {
      setLoading(false);
    }
  };

  const filteredBusinesses = businesses.filter(b => 
    b.nombre.toLowerCase().includes(search.toLowerCase()) ||
    (b.descripcion && b.descripcion.toLowerCase().includes(search.toLowerCase()))
  );

  if (loading) {
    return (
      <div className="retro-page">
        <div className="retro-bg">
          <div className="scanline" />
          <div className="grid-overlay" />
          <div className="glow glow-1" />
          <div className="glow glow-2" />
          <div className="floating-shapes">
            <div className="shape shape-1" />
            <div className="shape shape-2" />
            <div className="shape shape-3" />
          </div>
        </div>
        <Container className="py-5 position-relative" style={{ zIndex: 1 }}>
          <div className="text-center mb-5">
            <div className="skeleton mx-auto retro-title-glow" style={{ width: 200, height: 56, borderRadius: 4 }} />
          </div>
          <Row>
            {[1, 2, 3].map((i) => (
              <Col key={i} md={6} lg={4} className="mb-4">
                <div className="retro-card">
                  <div className="retro-card-header" />
                  <Card.Body className="p-4">
                    <SkeletonText lines={2} />
                  </Card.Body>
                </div>
              </Col>
            ))}
          </Row>
        </Container>
      </div>
    );
  }

  return (
    <div className="retro-page">
      <div className="retro-bg">
        <div className="scanline" />
        <div className="grid-overlay" />
        <div className="glow glow-1" />
        <div className="glow glow-2" />
        <div className="floating-shapes">
          <div className="shape shape-1" />
          <div className="shape shape-2" />
          <div className="shape shape-3" />
        </div>
      </div>

      <Container className="py-5 position-relative" style={{ zIndex: 1 }}>
        <div className="text-center mb-5">
          <div className="retro-badge mb-3">
            <span>SISTEMA DE RESERVAS v2.0</span>
          </div>
          <h1 className="retro-title">
            <span className="retro-title-main">APP</span>
            <span className="retro-title-accent">CITAS</span>
          </h1>
          <p className="retro-subtitle">
            Descubre y reserva en los mejores establecimientos
          </p>
        </div>

        <Row className="justify-content-center mb-5">
          <Col md={7}>
            <div className="retro-search">
              <InputGroup>
                <InputGroup.Text className="retro-search-icon">
                  <Search size={20} />
                </InputGroup.Text>
                <Form.Control
                  type="text"
                  placeholder="Buscar establecimiento..."
                  value={search}
                  onChange={(e) => setSearch(e.target.value)}
                  className="retro-search-input"
                />
              </InputGroup>
              <div className="retro-search-line" />
            </div>
          </Col>
        </Row>

        {error && (
          <div className="retro-alert retro-alert-danger animate-fade-in">
            {error}
          </div>
        )}

        <div className="retro-section-title">
          <span className="retro-section-number">01</span>
          <span className="retro-section-label">ESTABLECIMIENTOS DISPONIBLES</span>
          <div className="retro-section-line" />
        </div>

        <Row className="justify-content-center">
          {filteredBusinesses.map((business, index) => (
            <Col key={business.id} md={6} lg={4} className="mb-4">
              <div 
                className="retro-card"
                style={{ animationDelay: `${0.1 + index * 0.15}s` }}
                onClick={() => navigate(`/${business.slug}`)}
              >
                <div className="retro-card-glow" 
                  style={{ background: `linear-gradient(180deg, ${business.color_primario || '#00ff9f'}20, transparent)` }} 
                />
                <div 
                  className="retro-card-accent"
                  style={{ background: business.color_primario || '#00ff9f' }}
                />
                <div className="retro-card-pattern" />
                <Card.Body className="p-4">
                  <div className="d-flex align-items-center mb-4">
                    {business.logo_url ? (
                      <div className="retro-avatar">
                        <img
                          src={business.logo_url}
                          alt={business.nombre}
                          className="w-100 h-100"
                          style={{ objectFit: 'cover' }}
                          onError={(e) => e.target.style.display = 'none'}
                        />
                      </div>
                    ) : (
                      <div className="retro-avatar retro-avatar-icon">
                        <Shop size={28} />
                      </div>
                    )}

                    <div className="flex-grow-1">
